<script setup lang="ts">import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import BottomNav from '../../components/BottomNav.vue';import ServiceIcon from '../../components/ServiceIcon.vue';import{medicalApi,type NotificationItem}from'../../api/medical';import{currentPatient}from'../../stores/session';import{markOneMessageReadLocally,refreshUnreadMessageCount}from'../../stores/notification';const messages=ref<NotificationItem[]>([]),loading=ref(false);function messageIcon(title:string){if(title.includes('报告'))return 'compose';if(title.includes('系统'))return 'notification';return 'calendar'}function tone(item:NotificationItem){return item.isRead===0?'blue':'green'}async function load(){const patient=currentPatient.value;if(!patient)return;loading.value=true;try{const data=await medicalApi.notifications(patient.patientId);messages.value=data.list||[];await refreshUnreadMessageCount()}finally{loading.value=false}}async function open(item:NotificationItem){if(item.isRead===0&&currentPatient.value){await medicalApi.markRead(item.id,currentPatient.value.patientId);item.isRead=1;markOneMessageReadLocally()}}onShow(load)</script>
<template><view class="page-shell"><view class="page-title">消息中心</view><view class="banner card"><view><text class="banner-title">重要消息及时提醒</text><text>就医动态 · 系统通知 · 贴心服务</text></view><text class="mail">✉</text></view><view class="tabs"><text class="active">全部消息</text><text>未读消息</text><text>服务消息</text><text>系统通知</text></view><view v-if="loading" class="message card">正在加载消息…</view><view v-for="item in messages" :key="item.id" class="message card" @tap="open(item)"><view class="message-icon-platform"><ServiceIcon :type="messageIcon(item.title)" :tone="tone(item)"/></view><view><text class="message-title">{{item.title}}</text><text>{{item.content}}</text></view><text class="time">{{item.createdTime?.slice(5,16)}}</text></view><view v-if="!loading&&!messages.length" class="message card">暂无消息</view><BottomNav :active="2"/></view></template>
<style scoped lang="scss">.banner{height:185rpx;margin-top:28rpx;padding:32rpx;display:flex;align-items:center;background:linear-gradient(120deg,#fff,#c4e0ff)}.banner>view{flex:1;display:flex;flex-direction:column;gap:18rpx;color:#63779d;font-size:23rpx}.banner-title{font-size:30rpx;font-weight:700;color:#0a2054}.mail{font-size:90rpx;color:#4a8cf5}.tabs{display:flex;justify-content:space-between;padding:30rpx 4rpx 17rpx;color:#68758e;font-size:23rpx}.tabs .active{color:#2878ff;font-weight:700}.message-icon-platform{padding:7rpx;border-radius:23rpx;background:#f5f8fd}.message{margin-bottom:18rpx;padding:25rpx;display:flex;align-items:center;gap:18rpx}.message>view:nth-child(2){flex:1;display:flex;flex-direction:column;gap:9rpx;color:#75829a;font-size:20rpx}.message-title{font-size:25rpx;font-weight:650;color:#0a2054}.time{align-self:flex-start;color:#8490a8;font-size:19rpx}</style>
